#nullable enable // autogenerated

using System;
using MVZ2.GameContent.Buffs.Contraptions;
using MVZ2.GameContent.Commands;
using MVZ2.GameContent.Contraptions;
using MVZ2.GameContent.Damages;
using MVZ2.GameContent.Effects;
using MVZ2.GameContent.Pickups;
using MVZ2.GameContent.Seeds;
using MVZ2Logic.Blueprints;
using MVZ2Logic.Level;
using MVZ2.GameContent.Sprites;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Callbacks;
using MVZ2.Vanilla.Localization;
using MVZ2.Vanilla.Pickups;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Contents.Enemies;
using MVZ2Logic.Entities;
using MVZ2Logic.Modifiers;
using PVZEngine;
using PVZEngine.Buffs;
using PVZEngine.Callbacks;
using PVZEngine.Damages;
using PVZEngine.Entities;
using PVZEngine.Level;
using PVZEngine.Modifiers;
using UnityEngine;

namespace MVZ2.GameContent.Stages
{
    public class HeavyWeaponStageBehaviour : StageBehaviour
    {
        public HeavyWeaponStageBehaviour(StageDefinition stageDef) : base(stageDef)
        {
            AddModifier(new NamespaceIDModifier(LogicLevelProps.STARSHARD_DISABLE_ID, SetOperator.Set, VanillaBlueprintErrors.locked));
            AddModifier(new SpriteReferenceModifier(LogicAreaProps.STARSHARD_ICON, SetOperator.Set, VanillaSprites.snipenserLife));
            stageDef.AddTrigger(VanillaLevelCallbacks.PRE_ENTITY_TAKE_DAMAGE, PreContraptionTakeDamageCallback, filter: EntityTypes.PLANT);
            stageDef.AddTrigger(LevelCallbacks.POST_ENTITY_DEATH, PostContraptionDeathCallback, filter: EntityTypes.PLANT);
        }
        public override void Start(LevelEngine level)
        {
            base.Start(level);
            level.SetPickaxeActive(false);
            level.SetTriggerActive(false);
            level.SetStarshardCount(2);
            level.SetStarshardSlotCount(2);

            RespawnSnipenser(level);
        }
        public override void Update(LevelEngine level)
        {
            base.Update(level);
            if (level.CurrentWave >= 1)
            {
                var snipenserReference = GetSnipenserReference(level);
                var snipenser = snipenserReference?.GetEntity(level);
                if (!snipenser.ExistsAndAlive())
                {
                    if (level.GetStarshardCount() > 0)
                    {
                        RespawnSnipenser(level);
                        level.AddStarshardCount(-1);
                    }
                    else
                    {
                        level.GameOver(GameOverTypes.NO_ENEMY, null, VanillaStrings.DEATH_MESSAGE_SNIPENSER_LOST);
                    }
                }
                else if (!snipenser.IsFriendlyEntity())
                {
                    var damageEffects = new DamageEffectList(VanillaDamageEffects.INSTA_KILL);
                    snipenser.Die(damageEffects);
                }
            }
        }
        private void RespawnSnipenser(LevelEngine level)
        {
            SpawnOrFindRail(level)?.Let(rail =>
            {
                SpawnOrFindMinecart(level, rail)?.Let(cart =>
                {
                    cart.SetParent(rail);

                    SpawnOrFindSnipenser(level, cart)?.Let(snipenser =>
                    {
                        snipenser.RideOn(cart);
                        SetSnipenserReference(level, new EntityID(snipenser));
                        snipenser.AddBuff<DreamButterflyShieldBuff>();
                    });
                });
            });
        }

        private Entity? SpawnOrFindRail(LevelEngine level)
        {
            var rail = level.FindFirstEntity(VanillaEffectID.minecartRail);
            if (rail.ExistsAndAlive())
                return rail;
            return level.Spawn(VanillaEffectID.minecartRail, new Vector3(level.GetEntityColumnX(0), 0, level.GetLaneZ(2)), null);
        }
        private Entity? SpawnOrFindMinecart(LevelEngine level, Entity rail)
        {
            var minecart = level.FindFirstEntity(VanillaEffectID.minecartRideable);
            if (minecart.ExistsAndAlive())
                return minecart;
            return level.Spawn(VanillaEffectID.minecartRideable, rail.Position, rail);
        }
        private Entity? SpawnOrFindSnipenser(LevelEngine level, Entity cart)
        {
            var snipenser = level.FindFirstEntity(VanillaContraptionID.MegaSnipenser);
            if (snipenser.ExistsAndAlive())
                return snipenser;
            var param = new SpawnParams();
            param.SetProperty(LogicEntityProps.GRID_LAYERS, Array.Empty<NamespaceID>());
            param.SetProperty(LogicEntityProps.HP_BAR_VISIBILITY, HPBarVisibility.FORCE);
            return level.Spawn(VanillaContraptionID.MegaSnipenser, cart.Position, cart, param);
        }
        private void PreContraptionTakeDamageCallback(VanillaLevelCallbacks.PreTakeDamageParams param, CallbackResult result)
        {
            var input = param.input;
            var entity = input.Entity;
            var level = entity.Level;
            if (level.HasBehaviour(this) && level.IsGodMode())
            {
                var snipenserReference = GetSnipenserReference(level);
                if (snipenserReference != null && snipenserReference.IsEntity(entity))
                {
                    result.SetFinalValue(false);
                }
            }
        }
        private void PostContraptionDeathCallback(LevelCallbacks.EntityDeathParams param, CallbackResult result)
        {
            var entity = param.entity;
            var level = entity.Level;
            if (level.HasBehaviour(this))
            {
                var snipenserReference = GetSnipenserReference(level);
                if (snipenserReference != null && snipenserReference.IsEntity(entity))
                {
                    var rapidUpgrade = MegaSnipenser.GetRapidLevel(entity);
                    var spreadUpgrade = MegaSnipenser.GetSpreadLevel(entity);
                    var rapidCost = level.Content.GetSeedDefinition(VanillaBlueprintID.heavyWeaponRapid)?.GetCost() ?? 0;
                    var spreadCost = level.Content.GetSeedDefinition(VanillaBlueprintID.heavyWeaponSpread)?.GetCost() ?? 0;
                    var rapidRedStones = Mathf.Max(0, rapidCost - 25) / 25;
                    var spreadRedstones = Mathf.Max(0, spreadCost - 25) / 25;
                    var totalRedstones = rapidUpgrade * rapidRedStones + spreadUpgrade * spreadRedstones;

                    for (int i = 0; i < totalRedstones; i++)
                    {
                        entity.Produce(VanillaPickupID.redstone);
                    }

                    Explosion.Spawn(entity, entity.GetCenter(), 120);
                    entity.PlaySound(VanillaSoundID.largeExplosion);
                }
            }
        }

        public static EntityID? GetSnipenserReference(LevelEngine level) => level.GetProperty<EntityID>(PROP_SNIPENSER_REFERENCE);
        public static void SetSnipenserReference(LevelEngine level, EntityID? value) => level.SetProperty(PROP_SNIPENSER_REFERENCE, value);
        private const string PROP_REGION = "heavy_weapon_stage";
        [LevelPropertyRegistry(PROP_REGION)]
        public static readonly VanillaLevelPropertyMeta<EntityID> PROP_SNIPENSER_REFERENCE = new VanillaLevelPropertyMeta<EntityID>("snipenser_reference");
    }
}
